// Get task statistics for an epic
export function getEpicTaskStats(epicId: string): {
  total: number;
  completed: number;
  failed: number;
  inProgress: number;
  pending: number;
  unassigned: number;
} {
  const row = getDb()
    .prepare<
      {
        total: number;
        completed: number;
        failed: number;
        in_progress: number;
        pending: number;
        unassigned: number;
      },
      [string]
    >(
      `SELECT
        COUNT(*) as total,
        SUM(CASE WHEN status = 'completed' THEN 1 ELSE 0 END) as completed,
        SUM(CASE WHEN status = 'failed' THEN 1 ELSE 0 END) as failed,
        SUM(CASE WHEN status = 'in_progress' THEN 1 ELSE 0 END) as in_progress,
        SUM(CASE WHEN status = 'pending' THEN 1 ELSE 0 END) as pending,
        SUM(CASE WHEN status = 'unassigned' THEN 1 ELSE 0 END) as unassigned
      FROM agent_tasks WHERE epicId = ?`,
    )
    .get(epicId);

  return {
    total: row?.total ?? 0,
    completed: row?.completed ?? 0,
    failed: row?.failed ?? 0,
    inProgress: row?.in_progress ?? 0,
    pending: row?.pending ?? 0,
    unassigned: row?.unassigned ?? 0,
  };
}

// Get epic with progress calculation
export function getEpicWithProgress(id: string): EpicWithProgress | null {
  const epic = getEpicById(id);
  if (!epic) return null;

  const stats = getEpicTaskStats(id);
  const progress = stats.total > 0 ? Math.round((stats.completed / stats.total) * 100) : 0;

  return {
    ...epic,
    taskStats: stats,
    progress,
  };
}

