  if (filters?.search) {
    query += " AND (name LIKE ? OR description LIKE ? OR goal LIKE ?)";
    const searchTerm = `%${filters.search}%`;
    params.push(searchTerm, searchTerm, searchTerm);
  }

  query += " ORDER BY priority DESC, createdAt DESC";

  if (filters?.limit) {
    query += " LIMIT ?";
    params.push(filters.limit);
