  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
  const query = `SELECT * FROM swarm_repos ${whereClause} ORDER BY name ASC`;

  return getDb()
    .prepare<SwarmRepoRow, (string | number)[]>(query)
    .all(...params)
    .map(rowToSwarmRepo);
