 14→import { matchRoute } from "./utils";
 15→
 16→export async function handleSchedules(
 17→  req: IncomingMessage,
 18→  res: ServerResponse,
 19→  pathSegments: string[],
 20→  _queryParams: URLSearchParams,
 21→  _myAgentId: string | undefined,
 22→): Promise<boolean> {
 23→  // POST /api/schedules — Create a new schedule
 24→  if (matchRoute(req.method, pathSegments, "POST", ["api", "schedules"], true)) {
 25→    const chunks: Buffer[] = [];
 26→    for await (const chunk of req) {
 27→      chunks.push(chunk);
 28→    }
 29→    const body = JSON.parse(Buffer.concat(chunks).toString());
 30→
 31→    if (!body.name) {
 32→      res.writeHead(400, { "Content-Type": "application/json" });
 33→      res.end(JSON.stringify({ error: "Missing required field: name" }));
 34→      return true;
 35→    }
 36→
 37→    if (!body.taskTemplate) {
 38→      res.writeHead(400, { "Content-Type": "application/json" });
 39→      res.end(JSON.stringify({ error: "Missing required field: taskTemplate" }));
 40→      return true;
 41→    }
 42→
 43→    // Validate cron expression
 44→    if (body.cronExpression) {
 45→      try {
 46→        CronExpressionParser.parse(body.cronExpression);
