    res.end(JSON.stringify({ services }));
    return true;
  }

  // GET /api/scheduled-tasks - List all scheduled tasks (with optional filters: enabled, name)
  if (matchRoute(req.method, pathSegments, "GET", ["api", "scheduled-tasks"], true)) {
