 52→function formatInterval(ms: number): string {
 53→  const seconds = ms / 1000;
 54→  if (seconds < 60) return `${seconds}s`;
 55→  const minutes = seconds / 60;
 56→  if (minutes < 60) return `${minutes}m`;
 57→  const hours = minutes / 60;
 58→  if (hours < 24) return `${hours}h`;
 59→  return `${hours / 24}d`;
 60→}
