 62→function ScheduleTasks({ scheduleId }: { scheduleId: string }) {
 63→  const navigate = useNavigate();
 64→  const { data: agents } = useAgents();
 65→  const { data: tasksData, isLoading } = useTasks({ scheduleId, limit: 100 });
 66→
 67→  const agentMap = useMemo(() => {
 68→    const m = new Map<string, string>();
 69→    agents?.forEach((a) => {
 70→      m.set(a.id, a.name);
 71→    });
 72→    return m;
 73→  }, [agents]);
 74→
 75→  const columnDefs = useMemo<ColDef<AgentTask>[]>(
 76→    () => [
 77→      {
 78→        field: "task",
 79→        headerName: "Description",
 80→        flex: 1,
 81→        minWidth: 250,
 82→        cellRenderer: (params: { value: string }) => (
 83→          <span className="truncate">{params.value}</span>
 84→        ),
 85→      },
 86→      {
 87→        field: "status",
 88→        headerName: "Status",
 89→        width: 130,
 90→        cellRenderer: (params: { value: AgentTaskStatus }) => <StatusBadge status={params.value} />,
 91→      },
 92→      {
 93→        field: "agentId",
 94→        headerName: "Agent",
 95→        width: 150,
 96→        valueFormatter: (params) =>
 97→          params.value
 98→            ? (agentMap.get(params.value) ?? `${params.value.slice(0, 8)}...`)
 99→            : "Unassigned",
100→      },
101→      {
102→        headerName: "Elapsed",
103→        width: 100,
104→        valueGetter: (params) => {
105→          const task = params.data;
106→          if (!task) return "";
107→          const start = task.acceptedAt ?? task.createdAt;
108→          const end = task.finishedAt;
109→          const isActive =
110→            !end &&
111→            (task.status === "in_progress" ||
112→              task.status === "pending" ||
113→              task.status === "offered");
114→          return isActive ? formatElapsed(start) : end ? formatElapsed(start, end) : "—";
115→        },
116→      },
117→      {
118→        field: "createdAt",
119→        headerName: "Created",
120→        width: 150,
121→        valueFormatter: (params) => (params.value ? formatSmartTime(params.value) : ""),
122→      },
123→    ],
124→    [agentMap],
125→  );
126→
127→  const onRowClicked = useCallback(
128→    (event: RowClickedEvent<AgentTask>) => {
129→      if (event.data) navigate(`/tasks/${event.data.id}`);
130→    },
131→    [navigate],
132→  );
133→
134→  return (
135→    <DataGrid
136→      rowData={tasksData?.tasks ?? []}
137→      columnDefs={columnDefs}
138→      onRowClicked={onRowClicked}
139→      loading={isLoading}
140→      emptyMessage="No tasks created by this schedule"
141→      domLayout="autoHeight"
142→    />
143→  );
144→}
