426→function EditScheduleDialog({
427→  schedule,
428→  agents,
429→  open,
430→  onOpenChange,
431→  onSubmit,
432→}: {
433→  schedule: {
434→    name: string;
435→    taskTemplate: string;
436→    cronExpression?: string;
437→    intervalMs?: number;
438→    description?: string;
439→    taskType?: string;
440→    tags: string[];
441→    priority: number;
442→    targetAgentId?: string;
443→    timezone: string;
444→    model?: string;
445→  };
446→  agents: { id: string; name: string; isLead?: boolean }[] | undefined;
447→  open: boolean;
448→  onOpenChange: (open: boolean) => void;
449→  onSubmit: (data: Record<string, unknown>) => void;
450→}) {
451→  const [name, setName] = useState(schedule.name);
452→  const [taskTemplate, setTaskTemplate] = useState(schedule.taskTemplate);
453→  const [cronExpression, setCronExpression] = useState(schedule.cronExpression ?? "");
454→  const [intervalMinutes, setIntervalMinutes] = useState(
455→    schedule.intervalMs ? schedule.intervalMs / 60000 : 60,
456→  );
457→  const [scheduleType, setScheduleType] = useState<"cron" | "interval">(
458→    schedule.cronExpression ? "cron" : "interval",
459→  );
460→  const [description, setDescription] = useState(schedule.description ?? "");
461→  const [taskType, setTaskType] = useState(schedule.taskType ?? "");
462→  const [tags, setTags] = useState(schedule.tags.join(", "));
463→  const [priority, setPriority] = useState(schedule.priority);
464→  const [targetAgentId, setTargetAgentId] = useState(schedule.targetAgentId ?? "");
465→  const [timezone, setTimezone] = useState(schedule.timezone);
466→  const [model, setModel] = useState(schedule.model ?? "");
467→
468→  function handleSubmit(e: React.FormEvent) {
469→    e.preventDefault();
470→    const tagList = tags
471→      .split(",")
472→      .map((t) => t.trim())
473→      .filter(Boolean);
474→    onSubmit({
475→      name,
476→      taskTemplate,
477→      ...(scheduleType === "cron"
478→        ? { cronExpression, intervalMs: null }
479→        : { intervalMs: intervalMinutes * 60000, cronExpression: null }),
480→      description: description || null,
481→      taskType: taskType || null,
482→      tags: tagList,
483→      priority,
484→      targetAgentId: targetAgentId || null,
485→      timezone,
486→      model: model || null,
487→    });
488→  }
489→
490→  return (
491→    <Dialog open={open} onOpenChange={onOpenChange}>
492→      <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
493→        <form onSubmit={handleSubmit}>
494→          <DialogHeader>
495→            <DialogTitle>Edit Schedule</DialogTitle>
496→            <DialogDescription>Update schedule configuration.</DialogDescription>
497→          </DialogHeader>
498→          <div className="space-y-4 py-4">
499→            <div className="space-y-2">
500→              <Label>Name *</Label>
501→              <Input value={name} onChange={(e) => setName(e.target.value)} required />
502→            </div>
503→            <div className="space-y-2">
504→              <Label>Task Template *</Label>
505→              <Textarea
506→                value={taskTemplate}
507→                onChange={(e) => setTaskTemplate(e.target.value)}
508→                required
509→                rows={3}
510→              />
511→            </div>
512→            <div className="space-y-2">
513→              <Label>Schedule Type</Label>
514→              <div className="flex gap-2">
515→                <Button
516→                  type="button"
517→                  size="sm"
518→                  variant={scheduleType === "cron" ? "default" : "outline"}
519→                  onClick={() => setScheduleType("cron")}
520→                >
521→                  Cron
522→                </Button>
523→                <Button
524→                  type="button"
525→                  size="sm"
526→                  variant={scheduleType === "interval" ? "default" : "outline"}
527→                  onClick={() => setScheduleType("interval")}
528→                >
529→                  Interval
530→                </Button>
531→              </div>
532→            </div>
533→            {scheduleType === "cron" ? (
534→              <div className="space-y-2">
535→                <Label>Cron Expression *</Label>
536→                <Input
537→                  value={cronExpression}
538→                  onChange={(e) => setCronExpression(e.target.value)}
539→                  className="font-mono"
540→                  required
541→                />
542→              </div>
543→            ) : (
544→              <div className="space-y-2">
545→                <Label>Interval (minutes)</Label>
546→                <Input
547→                  type="number"
548→                  min={1}
549→                  value={intervalMinutes}
550→                  onChange={(e) => setIntervalMinutes(Number(e.target.value))}
551→                />
552→              </div>
553→            )}
554→            <div className="grid grid-cols-2 gap-4">
555→              <div className="space-y-2">
556→                <Label>Target Agent</Label>
557→                <Select
558→                  value={targetAgentId}
559→                  onValueChange={(v) => setTargetAgentId(v === "_none" ? "" : v)}
560→                >
561→                  <SelectTrigger>
562→                    <SelectValue placeholder="Task Pool" />
563→                  </SelectTrigger>
564→                  <SelectContent>
565→                    <SelectItem value="_none">Task Pool</SelectItem>
566→                    {agents?.map((a) => (
567→                      <SelectItem key={a.id} value={a.id}>
568→                        {a.name}
569→                        {a.isLead ? " (Lead)" : ""}
570→                      </SelectItem>
571→                    ))}
572→                  </SelectContent>
573→                </Select>
574→              </div>
575→              <div className="space-y-2">
576→                <Label>Priority (0–100)</Label>
577→                <Input
578→                  type="number"
579→                  min={0}
580→                  max={100}
581→                  value={priority}
582→                  onChange={(e) => setPriority(Number(e.target.value))}
583→                />
584→              </div>
585→            </div>
586→            <div className="grid grid-cols-2 gap-4">
587→              <div className="space-y-2">
588→                <Label>Task Type</Label>
589→                <Input value={taskType} onChange={(e) => setTaskType(e.target.value)} />
590→              </div>
591→              <div className="space-y-2">
592→                <Label>Model</Label>
593→                <Select value={model} onValueChange={(v) => setModel(v === "_none" ? "" : v)}>
594→                  <SelectTrigger>
595→                    <SelectValue placeholder="Default" />
596→                  </SelectTrigger>
597→                  <SelectContent>
598→                    <SelectItem value="_none">Default</SelectItem>
599→                    <SelectItem value="haiku">Haiku</SelectItem>
600→                    <SelectItem value="sonnet">Sonnet</SelectItem>
601→                    <SelectItem value="opus">Opus</SelectItem>
602→                  </SelectContent>
603→                </Select>
604→              </div>
605→            </div>
