                  placeholder="0 * * * *"
                  value={form.cronExpression}
                  onChange={(e) => setForm({ ...form, cronExpression: e.target.value })}
                  className="font-mono"
                  required={form.scheduleType === "cron"}
                />
              </div>
            ) : (
              <div className="space-y-2">
                <Label>Interval (minutes)</Label>
                <Input
                  type="number"
                  min={1}
                  value={form.intervalMinutes}
                  onChange={(e) => setForm({ ...form, intervalMinutes: Number(e.target.value) })}
                />
              </div>
            )}
            <div className="space-y-2">
              <Label>Description</Label>
              <Input
                placeholder="Optional description"
                value={form.description}
                onChange={(e) => setForm({ ...form, description: e.target.value })}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Target Agent</Label>
                <Select
                  value={form.targetAgentId}
                  onValueChange={(v) => setForm({ ...form, targetAgentId: v === "_none" ? "" : v })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Task Pool" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="_none">Task Pool</SelectItem>
                    {agents?.map((a) => (
                      <SelectItem key={a.id} value={a.id}>
                        {a.name}
                        {a.isLead ? " (Lead)" : ""}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Priority (0–100)</Label>
                <Input
                  type="number"
                  min={0}
                  max={100}
                  value={form.priority}
                  onChange={(e) => setForm({ ...form, priority: Number(e.target.value) })}
                />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Task Type</Label>
                <Input
                  placeholder="e.g. code, research"
                  value={form.taskType}
                  onChange={(e) => setForm({ ...form, taskType: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Model</Label>
                <Select
                  value={form.model}
                  onValueChange={(v) => setForm({ ...form, model: v === "_none" ? "" : v })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Default" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="_none">Default</SelectItem>
                    <SelectItem value="haiku">Haiku</SelectItem>
                    <SelectItem value="sonnet">Sonnet</SelectItem>
                    <SelectItem value="opus">Opus</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Timezone</Label>
                <Input
                  placeholder="UTC"
                  value={form.timezone}
                  onChange={(e) => setForm({ ...form, timezone: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Tags (comma-separated)</Label>
                <Input
                  placeholder="daily, sync"
                  value={form.tags}
                  onChange={(e) => setForm({ ...form, tags: e.target.value })}
                />
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Switch
                id="schedule-enabled"
                checked={form.enabled}
                onCheckedChange={(checked) => setForm({ ...form, enabled: checked })}
              />
              <Label htmlFor="schedule-enabled">Enabled</Label>
            </div>
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
              Cancel
            </Button>
            <Button
              type="submit"
              className="bg-primary hover:bg-primary/90"
              disabled={!form.name.trim() || !form.taskTemplate.trim()}
            >
              {editData ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

export default function SchedulesPage() {
  const navigate = useNavigate();
  const { data: schedules, isLoading } = useScheduledTasks();
  const { data: agents } = useAgents();
  const createSchedule = useCreateSchedule();
  const updateSchedule = useUpdateSchedule();
  const [dialogOpen, setDialogOpen] = useState(false);

  function handleCreateSubmit(data: ScheduleFormData) {
    const tags = data.tags
      .split(",")
      .map((t) => t.trim())
      .filter(Boolean);
    createSchedule.mutate({
      name: data.name,
      taskTemplate: data.taskTemplate,
      ...(data.scheduleType === "cron"
        ? { cronExpression: data.cronExpression }
        : { intervalMs: data.intervalMinutes * 60 * 1000 }),
      ...(data.description && { description: data.description }),
      ...(data.taskType && { taskType: data.taskType }),
      ...(tags.length > 0 && { tags }),
      ...(data.priority !== 50 && { priority: data.priority }),
      ...(data.targetAgentId && { targetAgentId: data.targetAgentId }),
      ...(data.timezone !== "UTC" && { timezone: data.timezone }),
      ...(data.model && { model: data.model }),
      enabled: data.enabled,
    });
  }

  const agentMap = useMemo(() => {
    const m = new Map<string, string>();
    agents?.forEach((a) => {
      m.set(a.id, a.name);
    });
    return m;
  }, [agents]);

  const handleToggleEnabled = useCallback(
    (schedule: ScheduledTask, enabled: boolean) => {
      updateSchedule.mutate({ id: schedule.id, data: { enabled } });
    },
    [updateSchedule],
  );

  const columnDefs = useMemo<ColDef<ScheduledTask>[]>(
    () => [
      {
        field: "name",
        headerName: "Name",
        flex: 1,
        minWidth: 200,
        cellRenderer: (params: { value: string }) => (
          <span className="font-semibold">{params.value}</span>
        ),
      },
      {
        field: "scheduleType",
        headerName: "Type",
        width: 110,
        cellRenderer: (params: { value?: string }) => (
          <Badge
            variant="outline"
            className={`text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase ${
              params.value === "one_time"
                ? "border-amber-500/30 text-amber-400"
                : "border-emerald-500/30 text-emerald-400"
            }`}
          >
            {params.value === "one_time" ? "One-time" : "Recurring"}
          </Badge>
        ),
      },
      {
        headerName: "Schedule",
        width: 200,
        minWidth: 160,
        valueGetter: (params) => {
          if (params.data?.scheduleType === "one_time") {
            return params.data?.nextRunAt
              ? `at ${formatSmartTime(params.data.nextRunAt)}`
              : params.data?.lastRunAt
                ? `ran ${formatSmartTime(params.data.lastRunAt)}`
                : "—";
          }
          if (params.data?.cronExpression) return params.data.cronExpression;
          if (params.data?.intervalMs) return `every ${formatInterval(params.data.intervalMs)}`;
          return "—";
        },
        cellRenderer: (params: { value: string }) => (
          <span className="font-mono text-xs text-muted-foreground">{params.value}</span>
        ),
      },
      {
        field: "targetAgentId",
        headerName: "Target Agent",
        width: 180,
        minWidth: 150,
        valueFormatter: (params) =>
          params.value ? (agentMap.get(params.value) ?? `${params.value.slice(0, 8)}...`) : "Pool",
      },
      {
        field: "nextRunAt",
        headerName: "Next Run",
        width: 150,
        valueFormatter: (params) => (params.value ? formatSmartTime(params.value) : "—"),
      },
      {
        field: "lastRunAt",
        headerName: "Last Run",
        width: 150,
        valueFormatter: (params) => (params.value ? formatSmartTime(params.value) : "Never"),
      },
      {
        field: "enabled",
        headerName: "Enabled",
        width: 100,
        cellRenderer: (params: ICellRendererParams<ScheduledTask>) => {
          const schedule = params.data;
          if (!schedule) return null;
          return (
            <div onClick={(e) => e.stopPropagation()} onKeyDown={(e) => e.stopPropagation()}>
              <Switch
                size="sm"
                checked={schedule.enabled}
                onCheckedChange={(checked) => handleToggleEnabled(schedule, checked)}
              />
            </div>
          );
        },
      },
    ],
    [agentMap, handleToggleEnabled],
  );

  const onRowClicked = useCallback(
    (event: RowClickedEvent<ScheduledTask>) => {
      // Skip navigation when clicking interactive elements (switch, button, etc.)
      const target = event.event?.target as HTMLElement | null;
      if (target?.closest('[data-slot="switch"], button')) return;
      if (event.data) navigate(`/schedules/${event.data.id}`);
    },
    [navigate],
  );

  const createButton = (
    <Button
      onClick={() => setDialogOpen(true)}
      size="sm"
      className="gap-1 bg-primary hover:bg-primary/90"
    >
      <Plus className="h-3.5 w-3.5" /> Create Schedule
    </Button>
  );

  if (!isLoading && (!schedules || schedules.length === 0)) {
    return (
      <div className="flex flex-col flex-1 min-h-0 gap-4">
        <div className="flex items-center justify-between">
          <h1 className="text-xl font-semibold">Schedules</h1>
          {createButton}
        </div>
        <div className="flex flex-col items-center justify-center py-16 text-muted-foreground">
          <Clock className="h-8 w-8 mb-2" />
          <p className="text-sm">No scheduled tasks</p>
        </div>
        <ScheduleDialog
          open={dialogOpen}
          onOpenChange={setDialogOpen}
          onSubmit={handleCreateSubmit}
        />
      </div>
    );
  }

  return (
    <div className="flex flex-col flex-1 min-h-0 gap-4">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">Schedules</h1>
        {createButton}
      </div>

      <DataGrid
        rowData={schedules ?? []}
        columnDefs={columnDefs}
        onRowClicked={onRowClicked}
        loading={isLoading}
        emptyMessage="No scheduled tasks"
      />

      <ScheduleDialog
        open={dialogOpen}
        onOpenChange={setDialogOpen}
        onSubmit={handleCreateSubmit}
      />
    </div>
  );
}

