  if (data.consecutiveErrors !== undefined) {
    updates.push("consecutiveErrors = ?");
    params.push(data.consecutiveErrors);
  }
  if (data.lastErrorAt !== undefined) {
    updates.push("lastErrorAt = ?");
    params.push(data.lastErrorAt);
