/**
 * Get in_progress tasks that haven't been updated within the given threshold.
 * Used by the heartbeat to detect potentially stalled tasks.
 */
export function getStalledInProgressTasks(thresholdMinutes: number = 30): AgentTask[] {
  const cutoff = new Date(Date.now() - thresholdMinutes * 60 * 1000).toISOString();
  return getDb()
    .prepare<AgentTaskRow, [string]>(
      `SELECT * FROM agent_tasks
       WHERE status = 'in_progress' AND lastUpdatedAt < ?
       ORDER BY lastUpdatedAt ASC`,
    )
    .all(cutoff)
    .map(rowToAgentTask);
}

/**
 * Get idle, non-lead, non-offline agents that have capacity for more tasks.
 * Used by the heartbeat for auto-assignment of pool tasks.
 */
export function getIdleWorkersWithCapacity(): Agent[] {
  const agents = getDb()
    .prepare<AgentRow, []>(
      `SELECT * FROM agents
       WHERE status = 'idle' AND isLead = 0`,
    )
    .all()
    .map(rowToAgent);

  return agents.filter((agent) => {
    const activeCount = getActiveTaskCount(agent.id);
    return activeCount < (agent.maxTasks ?? 1);
  });
}

/**
 * Get unassigned pool tasks ordered by priority (DESC) then creation time (ASC).
 * Used by the heartbeat for auto-assignment.
 */
export function getUnassignedPoolTasks(limit: number = 10): AgentTask[] {
  return getDb()
    .prepare<AgentTaskRow, [number]>(
      `SELECT * FROM agent_tasks
       WHERE status = 'unassigned'
       ORDER BY priority DESC, createdAt ASC
       LIMIT ?`,
    )
    .all(limit)
    .map(rowToAgentTask);
}

import { CronExpressionParser } from "cron-parser";
import {
  createTaskExtended,
  getDb,
  getDueScheduledTasks,
  getScheduledTaskById,
  updateScheduledTask,
} from "@/be/db";
import type { ScheduledTask } from "@/types";

let schedulerInterval: ReturnType<typeof setInterval> | null = null;
let isProcessing = false;

/**
 * Recover missed scheduled task runs from downtime.
 * Fires ONE catch-up run per schedule (not N missed runs).
 * Tags the task with "recovered" so it's distinguishable.
 */
async function recoverMissedSchedules(): Promise<void> {
  const now = new Date();
  const dueSchedules = getDueScheduledTasks();

  for (const schedule of dueSchedules) {
    if (!schedule.nextRunAt) continue;
    const missedBy = now.getTime() - new Date(schedule.nextRunAt).getTime();
    if (missedBy < 15000) continue; // Less than 15s — normal timing jitter

    console.log(
      `[Scheduler] Recovering missed schedule "${schedule.name}" ` +
        `(was due ${Math.round(missedBy / 1000)}s ago)`,
    );

    try {
      const tx = getDb().transaction(() => {
        createTaskExtended(schedule.taskTemplate, {
          creatorAgentId: schedule.createdByAgentId,
          taskType: schedule.taskType,
          tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "recovered"],
          priority: schedule.priority,
          agentId: schedule.targetAgentId,
          model: schedule.model,
          scheduleId: schedule.id,
          source: "schedule",
        });

        if (schedule.scheduleType === "one_time") {
          updateScheduledTask(schedule.id, {
            lastRunAt: now.toISOString(),
            nextRunAt: undefined,
            enabled: false,
            lastUpdatedAt: now.toISOString(),
          });
        } else {
          const nextRun = calculateNextRun(schedule, now);
          updateScheduledTask(schedule.id, {
            lastRunAt: now.toISOString(),
            nextRunAt: nextRun,
            lastUpdatedAt: now.toISOString(),
          });
        }
      });
      tx();

      if (schedule.scheduleType === "one_time") {
        console.log(`[Scheduler] One-time schedule "${schedule.name}" recovered and auto-disabled`);
      }
    } catch (err) {
      console.error(`[Scheduler] Error recovering "${schedule.name}":`, err);
    }
  }
}

/**
 * Calculate next run time based on cron expression or interval.
 * @param schedule The scheduled task
 * @param fromTime The time to calculate from (defaults to now)
 * @returns ISO string of next run time
 */
export function calculateNextRun(schedule: ScheduledTask, fromTime: Date = new Date()): string {
  if (schedule.cronExpression) {
    const interval = CronExpressionParser.parse(schedule.cronExpression, {
      currentDate: fromTime,
      tz: schedule.timezone || "UTC",
    });
    const nextDate = interval.next();
    const isoString = nextDate.toISOString();
    if (!isoString) {
      throw new Error("Failed to calculate next run time from cron expression");
    }
    return isoString;
  }

  if (schedule.intervalMs) {
    return new Date(fromTime.getTime() + schedule.intervalMs).toISOString();
  }

  throw new Error("Schedule must have cronExpression or intervalMs");
}

// Exponential backoff schedule for consecutive errors (in ms)
const ERROR_BACKOFF_MS = [
  60_000, // 1 minute
  300_000, // 5 minutes
  900_000, // 15 minutes
  1_800_000, // 30 minutes
  3_600_000, // 1 hour (cap)
];

const MAX_CONSECUTIVE_ERRORS = 5;

function getBackoffMs(consecutiveErrors: number): number {
  const idx = Math.min(consecutiveErrors - 1, ERROR_BACKOFF_MS.length - 1);
  return ERROR_BACKOFF_MS[Math.max(0, idx)] ?? ERROR_BACKOFF_MS[0]!;
}

/**
 * Execute a single scheduled task by creating an agent task.
 * Tracks consecutive errors and applies exponential backoff on failure.
 */
async function executeSchedule(schedule: ScheduledTask): Promise<void> {
  try {
    const tx = getDb().transaction(() => {
      const now = new Date().toISOString();

      createTaskExtended(schedule.taskTemplate, {
        creatorAgentId: schedule.createdByAgentId,
        taskType: schedule.taskType,
        tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`],
        priority: schedule.priority,
        agentId: schedule.targetAgentId,
        model: schedule.model,
        scheduleId: schedule.id,
        source: "schedule",
      });

      if (schedule.scheduleType === "one_time") {
        updateScheduledTask(schedule.id, {
          lastRunAt: now,
          nextRunAt: undefined,
          enabled: false,
          lastUpdatedAt: now,
          consecutiveErrors: 0,
          lastErrorAt: null,
          lastErrorMessage: null,
        });
        return null;
      }

      const nextRun = calculateNextRun(schedule, new Date());
      updateScheduledTask(schedule.id, {
        lastRunAt: now,
        nextRunAt: nextRun,
        lastUpdatedAt: now,
        consecutiveErrors: 0,
        lastErrorAt: null,
        lastErrorMessage: null,
      });

      return nextRun;
    });

    const nextRun = tx();
    if (schedule.scheduleType === "one_time") {
      console.log(`[Scheduler] Executed one-time schedule "${schedule.name}", auto-disabled`);
    } else {
      console.log(`[Scheduler] Executed schedule "${schedule.name}", next run: ${nextRun}`);
    }
  } catch (err) {
    const errorCount = (schedule.consecutiveErrors ?? 0) + 1;
    const now = new Date();
    const errorMsg = err instanceof Error ? err.message : String(err);

    console.error(
      `[Scheduler] Error executing "${schedule.name}" (${errorCount} consecutive):`,
      errorMsg,
    );

    const updates: {
      consecutiveErrors: number;
      lastErrorAt: string;
      lastErrorMessage: string;
      lastUpdatedAt: string;
      enabled?: boolean;
      nextRunAt?: string;
    } = {
      consecutiveErrors: errorCount,
      lastErrorAt: now.toISOString(),
      lastErrorMessage: errorMsg.slice(0, 500),
      lastUpdatedAt: now.toISOString(),
    };

    if (schedule.scheduleType === "one_time") {
      updates.enabled = false;
      console.warn(
        `[Scheduler] One-time schedule "${schedule.name}" failed, auto-disabled: ${errorMsg}`,
      );
    } else if (errorCount >= MAX_CONSECUTIVE_ERRORS) {
      updates.enabled = false;
      console.warn(
        `[Scheduler] Auto-disabled "${schedule.name}" after ${errorCount} consecutive errors`,
      );
    } else {
      const backoff = getBackoffMs(errorCount);
      updates.nextRunAt = new Date(now.getTime() + backoff).toISOString();
      console.log(`[Scheduler] Backing off "${schedule.name}" for ${backoff / 1000}s`);
    }

    updateScheduledTask(schedule.id, updates);
  }
}

/**
 * Start the scheduler polling loop.
 * @param intervalMs Polling interval in milliseconds (default: 10000)
 */
export function startScheduler(intervalMs = 10000): void {
  if (schedulerInterval) {
    console.log("[Scheduler] Already running");
    return;
  }

  console.log(`[Scheduler] Starting with ${intervalMs}ms polling interval`);

  // Recover missed schedules from downtime, then run normal processing
  void recoverMissedSchedules().then(() => processSchedules());

  schedulerInterval = setInterval(async () => {
    await processSchedules();
  }, intervalMs);
}

/**
 * Process all due schedules (called by interval).
 */
async function processSchedules(): Promise<void> {
  if (isProcessing) return;
  isProcessing = true;

  try {
    const dueSchedules = getDueScheduledTasks();

    for (const schedule of dueSchedules) {
      try {
        await executeSchedule(schedule);
      } catch (err) {
        console.error(`[Scheduler] Error executing "${schedule.name}":`, err);
      }
    }
  } finally {
    isProcessing = false;
  }
}

/**
 * Stop the scheduler polling loop.
 */
export function stopScheduler(): void {
  if (schedulerInterval) {
    clearInterval(schedulerInterval);
    schedulerInterval = null;
    isProcessing = false;
    console.log("[Scheduler] Stopped");
  }
}

/**
 * Run a schedule immediately (manual trigger).
 * Does NOT update nextRunAt - the regular schedule continues unaffected.
 * @param scheduleId The ID of the schedule to run
 */
export async function runScheduleNow(scheduleId: string): Promise<void> {
  const schedule = getScheduledTaskById(scheduleId);
  if (!schedule) {
    throw new Error(`Schedule not found: ${scheduleId}`);
  }
  if (!schedule.enabled) {
    throw new Error(`Schedule is disabled: ${schedule.name}`);
  }

  // Wrap in transaction to ensure atomicity of task creation and schedule update
  const tx = getDb().transaction(() => {
    const now = new Date().toISOString();

    // Create the actual task
    createTaskExtended(schedule.taskTemplate, {
      creatorAgentId: schedule.createdByAgentId,
      taskType: schedule.taskType,
      tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "manual-run"],
      priority: schedule.priority,
      agentId: schedule.targetAgentId,
      model: schedule.model,
      scheduleId: schedule.id,
      source: "schedule",
    });

    if (schedule.scheduleType === "one_time") {
      updateScheduledTask(schedule.id, {
        lastRunAt: now,
        nextRunAt: undefined,
        enabled: false,
        lastUpdatedAt: now,
      });
    } else {
      // Only update lastRunAt, not nextRunAt (to not affect regular schedule)
      updateScheduledTask(schedule.id, {
        lastRunAt: now,
        lastUpdatedAt: now,
      });
    }
  });

  tx();

  if (schedule.scheduleType === "one_time") {
    console.log(
      `[Scheduler] Manually executed one-time schedule "${schedule.name}", auto-disabled`,
    );
  } else {
    console.log(`[Scheduler] Manually executed schedule "${schedule.name}"`);
  }
}

import type { IncomingMessage, ServerResponse } from "node:http";
import { CronExpressionParser } from "cron-parser";
import {
  createScheduledTask,
  createTaskExtended,
  deleteScheduledTask,
  getAgentById,
  getDb,
  getScheduledTaskById,
  getScheduledTaskByName,
  updateScheduledTask,
} from "../be/db";
import { calculateNextRun } from "../scheduler/scheduler";
import { matchRoute } from "./utils";

export async function handleSchedules(
  req: IncomingMessage,
  res: ServerResponse,
  pathSegments: string[],
  _queryParams: URLSearchParams,
  _myAgentId: string | undefined,
): Promise<boolean> {
  // POST /api/schedules — Create a new schedule
  if (matchRoute(req.method, pathSegments, "POST", ["api", "schedules"], true)) {
    const chunks: Buffer[] = [];
    for await (const chunk of req) {
      chunks.push(chunk);
    }
    const body = JSON.parse(Buffer.concat(chunks).toString());

    if (!body.name) {
      res.writeHead(400, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Missing required field: name" }));
      return true;
    }

    if (!body.taskTemplate) {
      res.writeHead(400, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Missing required field: taskTemplate" }));
      return true;
    }

    const isOneTime = body.scheduleType === "one_time";

    // Validate params based on schedule type
    if (isOneTime) {
      if (body.cronExpression || body.intervalMs) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(
          JSON.stringify({
            error:
              "One-time schedules cannot use cronExpression or intervalMs. Use delayMs or runAt.",
          }),
        );
        return true;
      }
      if (!body.delayMs && !body.runAt) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "One-time schedules require either delayMs or runAt." }));
        return true;
      }
      if (body.delayMs && body.runAt) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "Provide either delayMs or runAt, not both." }));
        return true;
      }
      if (body.runAt && new Date(body.runAt).getTime() <= Date.now()) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "runAt must be in the future." }));
        return true;
      }
    } else {
      if (body.delayMs || body.runAt) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(
          JSON.stringify({
            error:
              "delayMs and runAt are only for one-time schedules. Set scheduleType to 'one_time'.",
          }),
        );
        return true;
      }
    }

    // Validate cron expression
    if (body.cronExpression) {
      try {
        CronExpressionParser.parse(body.cronExpression);
      } catch {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "Invalid cron expression" }));
        return true;
      }
    }

    // Check for duplicate name
    const existing = getScheduledTaskByName(body.name);
    if (existing) {
      res.writeHead(409, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Schedule with this name already exists" }));
      return true;
    }

    // Validate target agent if provided
    if (body.targetAgentId) {
      const agent = getAgentById(body.targetAgentId);
      if (!agent) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "Target agent not found" }));
        return true;
      }
    }

    try {
      // Calculate nextRunAt before creation
      let nextRunAt: string | undefined;
      if (body.enabled === false) {
        nextRunAt = undefined;
      } else if (isOneTime) {
        nextRunAt = body.delayMs ? new Date(Date.now() + body.delayMs).toISOString() : body.runAt;
      } else {
        const tempSchedule = {
          cronExpression: body.cronExpression || null,
          intervalMs: body.intervalMs || null,
          timezone: body.timezone || "UTC",
        };
        if (tempSchedule.cronExpression || tempSchedule.intervalMs) {
          // biome-ignore lint/suspicious/noExplicitAny: need partial ScheduledTask for calculateNextRun
          nextRunAt = calculateNextRun(tempSchedule as any);
        }
      }

      const schedule = createScheduledTask({
        name: body.name,
        description: body.description,
        cronExpression: body.cronExpression,
        intervalMs: body.intervalMs,
        taskTemplate: body.taskTemplate,
        taskType: body.taskType,
        tags: body.tags,
        priority: body.priority,
        targetAgentId: body.targetAgentId,
        enabled: body.enabled,
        nextRunAt,
        timezone: body.timezone,
        model: body.model,
        scheduleType: body.scheduleType,
      });

      res.writeHead(201, { "Content-Type": "application/json" });
      res.end(JSON.stringify(schedule));
    } catch (_error) {
      res.writeHead(500, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Failed to create schedule" }));
    }
    return true;
  }

  // POST /api/schedules/:id/run — Run a schedule immediately
  if (matchRoute(req.method, pathSegments, "POST", ["api", "schedules", null, "run"])) {
    const scheduleId = pathSegments[2]!;
    const schedule = getScheduledTaskById(scheduleId);

    if (!schedule) {
      res.writeHead(404, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Schedule not found" }));
      return true;
    }

    if (!schedule.enabled) {
      res.writeHead(400, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Schedule is disabled" }));
      return true;
    }

    try {
      const now = new Date().toISOString();

      const task = getDb().transaction(() => {
        const createdTask = createTaskExtended(schedule.taskTemplate, {
          creatorAgentId: schedule.createdByAgentId,
          taskType: schedule.taskType,
          tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "manual-run"],
          priority: schedule.priority,
          agentId: schedule.targetAgentId,
          model: schedule.model,
          scheduleId: schedule.id,
          source: "schedule",
        });

        if (schedule.scheduleType === "one_time") {
          updateScheduledTask(schedule.id, {
            lastRunAt: now,
            nextRunAt: undefined,
            enabled: false,
            lastUpdatedAt: now,
          });
        } else {
          updateScheduledTask(schedule.id, {
            lastRunAt: now,
            lastUpdatedAt: now,
          });
        }

        return createdTask;
      })();

      const updatedSchedule = getScheduledTaskById(scheduleId);

      res.writeHead(200, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ schedule: updatedSchedule, task }));
    } catch (_error) {
      res.writeHead(500, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Failed to run schedule" }));
    }
    return true;
  }

  // GET /api/schedules/:id — Get single schedule
  if (matchRoute(req.method, pathSegments, "GET", ["api", "schedules", null])) {
    const scheduleId = pathSegments[2]!;
    const schedule = getScheduledTaskById(scheduleId);

    if (!schedule) {
      res.writeHead(404, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Schedule not found" }));
      return true;
    }

    res.writeHead(200, { "Content-Type": "application/json" });
    res.end(JSON.stringify(schedule));
    return true;
  }

  // PUT /api/schedules/:id — Update a schedule
  if (matchRoute(req.method, pathSegments, "PUT", ["api", "schedules", null])) {
    const scheduleId = pathSegments[2]!;
    const chunks: Buffer[] = [];
    for await (const chunk of req) {
      chunks.push(chunk);
    }
    const body = JSON.parse(Buffer.concat(chunks).toString());

    const existing = getScheduledTaskById(scheduleId);
    if (!existing) {
      res.writeHead(404, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Schedule not found" }));
      return true;
    }

    // Reject updates on completed one-time schedules
    if (existing.scheduleType === "one_time" && !existing.enabled && existing.lastRunAt) {
      res.writeHead(400, { "Content-Type": "application/json" });
      res.end(
        JSON.stringify({
          error: "One-time schedule has already executed. Create a new one instead.",
        }),
      );
      return true;
    }

    // Validate new cron expression if provided
    if (body.cronExpression) {
      try {
        CronExpressionParser.parse(body.cronExpression);
      } catch {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "Invalid cron expression" }));
        return true;
      }
    }

    // Validate new target agent if provided
    if (body.targetAgentId) {
      const agent = getAgentById(body.targetAgentId);
      if (!agent) {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "Target agent not found" }));
        return true;
      }
    }

    // Validate name uniqueness if changing name
    if (body.name && body.name !== existing.name) {
      const nameConflict = getScheduledTaskByName(body.name);
      if (nameConflict) {
        res.writeHead(409, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ error: "Schedule with this name already exists" }));
        return true;
      }
    }

    // Recalculate nextRunAt when timing fields or enabled status changes
    const newEnabled = body.enabled !== undefined ? body.enabled : existing.enabled;
    if (existing.scheduleType === "one_time") {
      // One-time schedules: no recalculation via cron/interval
      if (!newEnabled) {
        body.nextRunAt = null;
      }
    } else {
      if (!newEnabled) {
        body.nextRunAt = null;
      } else if (
        body.cronExpression !== undefined ||
        body.intervalMs !== undefined ||
        (body.enabled === true && !existing.enabled)
      ) {
        const merged = {
          cronExpression: body.cronExpression ?? existing.cronExpression,
          intervalMs: body.intervalMs ?? existing.intervalMs,
          timezone: body.timezone ?? existing.timezone,
        };
        if (merged.cronExpression || merged.intervalMs) {
          // biome-ignore lint/suspicious/noExplicitAny: need partial ScheduledTask for calculateNextRun
          body.nextRunAt = calculateNextRun(merged as any);
        }
      }
    }

    const schedule = updateScheduledTask(scheduleId, body);
    res.writeHead(200, { "Content-Type": "application/json" });
    res.end(JSON.stringify(schedule));
    return true;
  }

  // DELETE /api/schedules/:id — Delete a schedule
  if (matchRoute(req.method, pathSegments, "DELETE", ["api", "schedules", null])) {
    const scheduleId = pathSegments[2]!;
    const deleted = deleteScheduledTask(scheduleId);

    if (!deleted) {
      res.writeHead(404, { "Content-Type": "application/json" });
      res.end(JSON.stringify({ error: "Schedule not found" }));
      return true;
    }

    res.writeHead(200, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ success: true }));
    return true;
  }

  return false;
}

